9. namespace Azure.ResourceManager
10. {
11.     /// <summary>
12.     /// ArmEnvrionment represents the information of an Azure Cloud environment.
13.     /// </summary>
14.     public readonly struct ArmEnvironment : IEquatable<ArmEnvironment>
15.     {
16.         // name after the `name` property of returned audience from https://management.azure.com/metadata/endpoints?api-version=2019-11-01
17.         /// <summary> Azure Public Cloud. </summary>
18.         public static readonly ArmEnvironment AzurePublicCloud = new(new Uri("https://management.azure.com"), "https://management.azure.com/");
19. 
20.         /// <summary> Azure China Cloud. </summary>
21.         public static readonly ArmEnvironment AzureChina = new(new Uri("https://management.chinacloudapi.cn"), "https://management.chinacloudapi.cn");
22. 
23.         /// <summary> Azure US Government. </summary>
24.         public static readonly ArmEnvironment AzureGovernment = new(new Uri("https://management.usgovcloudapi.net"), "https://management.usgovcloudapi.net");
25. 
26.         /// <summary> Azure German Cloud. </summary>
27.         public static readonly ArmEnvironment AzureGermany = new(new Uri("https://management.microsoftazure.de"), "https://management.microsoftazure.de");
28. 
29.         /// <summary>
30.         /// Gets base URI of the management API endpoint.
31.         /// </summary>
32.         public readonly Uri Endpoint { get; }
33. 
34.         /// <summary>
35.         /// Gets authentication audience.
36.         /// </summary>
37.         public readonly string Audience { get; }
38. 
39.         /// <summary>
40.         /// Gets default authentication scope.
41.         /// </summary>
42.         public string DefaultScope { get; }
43. 
44.         /// <summary>
45.         /// Construct an <see cref="ArmEnvironment"/> using the given value.
46.         /// </summary>
47.         /// <param name="endpoint">Management API endpoint base URI.</param>
48.         /// <param name="audience">Authentication audience.</param>
49.         public ArmEnvironment(Uri endpoint, string audience)
50.         {
51.             Argument.AssertNotNull(endpoint, nameof(endpoint));
52.             Argument.AssertNotNullOrWhiteSpace(audience, nameof(audience));
53. 
54.             Endpoint = endpoint;
55.             Audience = audience;
56.             DefaultScope = $"{Audience}/.default";
57.         }
58. 
59.         /// <summary> Determines if two <see cref="ArmEnvironment"/> values are the same. </summary>
60.         public static bool operator ==(ArmEnvironment left, ArmEnvironment right) => left.Equals(right);
61. 
62.         /// <summary> Determines if two <see cref="ArmEnvironment"/> values are not the same. </summary>internal
63.         public static bool operator !=(ArmEnvironment left, ArmEnvironment right) => !left.Equals(right);
64. 
65.         /// <inheritdoc />
66.         [EditorBrowsable(EditorBrowsableState.Never)]
67.         public override bool Equals(object obj) => obj is ArmEnvironment other && Equals(other);
68. 
69.         /// <inheritdoc />
70.         public bool Equals(ArmEnvironment other) => string.Equals(Audience, other.Audience, StringComparison.Ordinal) && Endpoint.Equals(other.Endpoint);
71. 
72.         /// <inheritdoc />
73.         [EditorBrowsable(EditorBrowsableState.Never)]
74.         public override int GetHashCode()
75.         {
76.             return HashCodeBuilder.Combine(Endpoint, Audience);
77.         }
78. 
79.         /// <inheritdoc />
80.         public override string ToString() => JsonSerializer.Serialize(this);
81.     }
82. }
